    "Сегмент, мітка і коментар": "セグメント、ラベル、コメント",
    "fn parse_age(text: &str) -> Result<i32, String> { match text.parse::<i32>() { Ok(age) => Ok(age), Err(_) => Err(String::from(\"Не число\")), } } fn main() { match parse_age(\"21\") { Ok(age) => println!(\"Вік: {}\", age), Err(error) => println!(\"Помилка: {}\", error), } }": "fn parse_age(text: &str) -> Result<i32, String> { match text.parse::<i32>() { Ok(年齢) => Ok(年齢), Err(_) => Err(String::from(\"非数値\")), } } fn main() { match parse_age(\"21\") { Ok(年齢) => println!(\"年齢: {}\", age), Err(error) => println!(\"Error: {}\", error), } }",
